      zh: { title: '上学、出行与日常变化', summary: '为什么日常变化会增加不确定性，以及在一天不那么可预测时，清晰的支持画面为什么更重要。', category: '家庭支持', terms: ['学校', '出行', '日常安排', '交接'], sections: [{ title: '不那么可预测的日子', body: '学校活动、出行、延误、错过进餐和不同的照看安排都会让一天更难判断。' }, { title: '共享可见性很重要', body: '当日常发生变化时，父母和支持型成年人更需要看到同一画面，并知道谁在响应。' }, { title: '简单胜过拥挤', body: '在过渡场景下，家庭通常更需要更少页面和更多清晰度。简单的状态视图往往比大仪表盘更有帮助。' }] },
      ja: { title: '学校、移動、日課の変化', summary: '日課の変化が不確実さを増やす理由と、予測しづらい日にこそ分かりやすい支援の見取り図が役立つ理由を説明します。', category: '家族支援', terms: ['学校', '移動', '日課', '引き継ぎ'], sections: [{ title: '予測しづらい日', body: '学校行事、移動、遅れ、食事の抜け、見守り体制の変化は、その日を読みづらくします。' }, { title: '共有された見え方が重要', body: '日課が変わるときほど、保護者と支援する大人が同じ画面を見て、誰が対応しているか分かることが重要です。' }, { title: 'シンプルさが勝つ', body: '移行の多い日は、多くの画面よりも少ない画面と高い明確さが役立ちます。大きなダッシュボードよりシンプルな状態表示の方が有用なことが多いです。' }] },
      pt: { title: 'Escola, viagens e mudanças de rotina', summary: 'Por que mudanças de rotina podem aumentar a incerteza e por que uma visão mais clara ajuda mais quando o dia é menos previsível.', category: 'Apoio Familiar', terms: ['escola', 'viagem', 'rotina', 'passagem'], sections: [{ title: 'Dias menos previsíveis', body: 'Eventos escolares, viagens, atrasos, refeições perdidas e mudanças de supervisão podem tornar o dia mais difícil de ler.' }, { title: 'Visibilidade compartilhada importa', body: 'Quando a rotina muda, torna-se ainda mais importante que pais e adultos de apoio vejam a mesma imagem e saibam quem está respondendo.' }, { title: 'O simples vence', body: 'Durante transições, as famílias geralmente precisam de menos telas e mais clareza. Uma visão simples costuma ajudar mais do que um grande painel.' }] },
      he: { title: 'בית ספר, נסיעות ושינויים בשגרה', summary: 'למה שינויים בשגרה יכולים להגדיל את אי-הוודאות ולמה תמונת תמיכה ברורה יותר חשובה במיוחד כשהיום פחות צפוי.', category: 'תמיכת משפחה', terms: ['בית ספר', 'נסיעה', 'שגרה', 'העברה'], sections: [{ title: 'ימים פחות צפויים', body: 'אירועי בית ספר, נסיעות, עיכובים, ארוחות שהוחמצו ושינויי השגחה יכולים להפוך את היום לקשה יותר לקריאה.' }, { title: 'נראות משותפת חשובה', body: 'כשהשגרה משתנה, חשוב עוד יותר שהורים ומבוגרים תומכים יראו את אותה תמונה ויידעו מי מגיב.' }, { title: 'פשוט עדיף על עמוס', body: 'במעברים משפחות בדרך כלל צריכות פחות מסכים ויותר בהירות. תצוגת מצב פשוטה מועילה לעיתים יותר מלוח גדול.' }] },
      ar: { title: 'المدرسة والسفر وتغيّر الروتين', summary: 'لماذا يمكن لتغير الروتين أن يزيد عدم اليقين، ولماذا تساعد صورة دعم أوضح أكثر عندما يكون اليوم أقل قابلية للتوقع.', category: 'دعم الأسرة', terms: ['المدرسة', 'السفر', 'الروتين', 'التسليم'], sections: [{ title: 'أيام أقل قابلية للتوقع', body: 'فعاليات المدرسة والسفر والتأخير وفوات الوجبات وتغيرات الإشراف كلها قد تجعل قراءة اليوم أصعب.' }, { title: 'الرؤية المشتركة مهمة', body: 'عندما يتغير الروتين، يصبح من الأهم أن يرى الآباء والبالغون الداعمون الصورة نفسها وأن يعرفوا من يستجيب.' }, { title: 'البساطة تتفوق على الازدحام', body: 'أثناء الانتقالات تحتاج الأسر عادةً إلى شاشات أقل ووضوح أكبر. وغالباً ما تكون نظرة الحالة البسيطة أنفع من لوحة كبيرة.' }] },
