      fr: { title: 'Jours de maladie, stress et changements inattendus', summary: 'Comment la maladie, le stress et les ruptures de routine peuvent modifier la glycémie et rendre l’aide à la décision moins directe.', category: 'Sécurité', terms: ['maladie', 'stress', 'changement inattendu', 'instabilité'], sections: [{ title: 'Pourquoi le schéma change', body: 'Le stress, la maladie et le sommeil perturbé peuvent changer le comportement de la glycémie de façon moins prévisible qu’un jour ordinaire.' }, { title: 'Faire confiance, mais vérifier', body: 'Un bon produit peut encore aider en rendant le signal actuel lisible, mais l’observation directe et la prudence comptent encore plus lors de journées instables.' }, { title: 'Quand accélérer le recours à l’aide', body: 'Si une personne paraît très mal, inhabituellement fatiguée, confuse ou difficile à réveiller, le plus sûr est d’obtenir rapidement une aide directe.' }] },
      de: { title: 'Krankheitstage, Stress und unerwartete Veränderungen', summary: 'Wie Krankheit, Stress und plötzliche Routinebrüche die Glukose verändern und Unterstützung weniger geradlinig machen können.', category: 'Sicherheit', terms: ['Krankheit', 'Stress', 'unerwartete Veränderung', 'Instabilität'], sections: [{ title: 'Warum sich das Muster ändert', body: 'Stress, Krankheit und gestörter Schlaf können das Glukoseverhalten weniger vorhersehbar machen als an einem gewöhnlichen Tag.' }, { title: 'Vertrauen, aber prüfen', body: 'Ein gutes Produkt kann helfen, indem es das aktuelle Signal lesbar macht, doch direkte Beobachtung und Vorsicht sind an instabilen Tagen noch wichtiger.' }, { title: 'Wann schneller Hilfe geholt werden sollte', body: 'Wenn jemand sehr unwohl wirkt, ungewöhnlich müde, verwirrt oder schwer zu wecken ist, ist direkte Hilfe der sicherste Weg.' }] },
